// 获取上一步 AI 节点的输出文本
const rawText = $input.first().json.text;

// 1. 去掉 markdown 的代码块标记 (```json 和 ```)
const cleanText = rawText.replace(/```json/g, '').replace(/```/g, '').trim();

// 2. 将字符串解析为真正的 JSON 对象
const jsonData = JSON.parse(cleanText);

// 3. 返回给 n8n，让它把每一篇文章当成一个独立的 Item
return jsonData;

// 获取 Firecrawl 返回的 data 数组
const items = $input.first().json.data;

// 直接返回这个数组，n8n 会自动识别为多条数据
return items;

const allInputItems = $input.all();
const sourceItems = $('Edit Fields').all();

return allInputItems.map((item, i) => {
  const rawText = (item.json.text || '').replace(/```json/g, '').replace(/```/g, '').trim();

  let result = { is_relevant: false, confidence: 'low', reason: '解析失败' };
  try {
    result = JSON.parse(rawText);
  } catch(e) {
    const match = rawText.match(/\{[^{}]+\}/s);
    if (match) {
      try { result = JSON.parse(match[0]); } catch(e2) {}
    }
  }

  const orig = (sourceItems[i] && sourceItems[i].json) ? sourceItems[i].json : {};

  return {
    json: {
      title:            orig.title    || '',
      abstract:         orig.abstract || '',
      link:             orig.link     || '',
      date:             orig.date     || '',
      is_relevant:      result.is_relevant === true,
      confidence:       result.confidence  || 'low',
      relevance_reason: result.reason      || ''
    }
  };
});

const items = $input.all();
const allOriginals = $('字段映射1').all();

const results = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const orig = allOriginals[i]?.json || {};

  let finalSummary = '', finalTitle = '', translatedAbstract = '', seoKeywords = '';
  try {
    const raw = item.json.output || item.json.text || '';
    const fo = raw.indexOf('{'), lc = raw.lastIndexOf('}');
    if (fo !== -1 && lc !== -1) {
      const p = JSON.parse(raw.substring(fo, lc + 1));
      if (p.summary)             finalSummary       = p.summary;
      if (p.translated_title)    finalTitle         = p.translated_title;
      if (p.translated_abstract) translatedAbstract = p.translated_abstract;
      if (p.seo_keywords)        seoKeywords        = p.seo_keywords;
    }
  } catch(e) {}

  results.push({
    json: {
      ...orig,
      is_relevant:         true,
      summary:             finalSummary,
      title:               finalTitle || orig.original_title || orig.title || '标题缺失',
      translated_abstract: translatedAbstract,
      seo_keywords:        seoKeywords
    }
  });
}
return results;

