// 从Science文章Markdown中提取结构化内容
// 优先级：Structured Abstract > Abstract > Editor's summary

function extractSection(markdown, sectionName) {
  const escaped = sectionName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp('##\\s+' + escaped + '\\s*\\n([\\s\\S]*?)(?=\\n##\\s|$)', 'i');
  const match = markdown.match(regex);
  if (match && match[1]) {
    return match[1]
      .replace(/!\[.*?\]\(.*?\)/g, '')
      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }
  return null;
}

const items = $input.all();

return items.map(item => {
  const markdown = item.json.markdown || '';
  const metadata = item.json.metadata || {};

  const structuredAbstract = extractSection(markdown, 'Structured Abstract');
  const plainAbstract      = extractSection(markdown, 'Abstract');
  const editorsSummary     = extractSection(markdown, "Editor's summary");

  const bestContent =
    structuredAbstract ||
    plainAbstract ||
    editorsSummary ||
    metadata.citation_abstract ||
    metadata.description ||
    metadata.ogDescription ||
    '';

  const rawTitle = metadata.title || metadata.ogTitle || metadata['og:title'] || '';
  const title = rawTitle.replace(/\s*\|\s*Science\s*$/i, '').trim();

  return {
    json: {
      title:               title,
      abstract:            bestContent,
      editors_summary:     editorsSummary     || '',
      structured_abstract: structuredAbstract || '',
      plain_abstract:      plainAbstract      || '',
      link:    metadata.url || metadata.ogUrl || metadata['og:url'] || '',
      journal: 'Science'
    }
  };
});

