// 把 RSS 的 /doi/abs/xxx?af=R 清理成 /doi/xxx 正式文章页
return $input.all().map(item => {
  const rawLink = item.json.link || '';
  const cleanLink = rawLink
    .replace('/doi/abs/', '/doi/')  // 去掉 /abs/ 变成正式文章页
