// 从 HTTP 获取的原始 RSS/XML 文本中解析所有条目（含 dc:type）
const xmlText = $input.first().json.data;
if (!xmlText) return [{ json: { error: '未获取到XML内容' } }];

// 通用字段提取：支持 dc:creator、content:encoded 等带冒号的标签
function getTag(xml, tag) {
  const esc = tag.replace(/[.*+?^${}()|[\]\\]/g, '\\$&').replace(/:/g, '\\:');
  const re = new RegExp('<' + esc + '[^>]*>([\\s\\S]*?)<\\/' + esc + '>', 'i');
  const m = xml.match(re);
  if (!m) return '';
  return m[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').trim();
}

// 拆分 <item ...> ... </item> 块（兼容 RSS 1.0 RDF 和 RSS 2.0）
const parts = xmlText.split(/<item[\s>]/i);
const items = parts.slice(1).map(p => {
  const end = p.indexOf('</item>');
  return end !== -1 ? p.substring(0, end) : p;
}).filter(p => p.trim());

return items.map(block => {
  const link        = getTag(block, 'link');
  const dcType      = getTag(block, 'dc:type');
  const dcCreator   = getTag(block, 'dc:creator');
  const dcDate      = getTag(block, 'dc:date');
  const dcSource    = getTag(block, 'dc:source');
  const encoded     = getTag(block, 'content:encoded');
  const description = getTag(block, 'description');

  return {
    json: {
      title:                   getTag(block, 'title'),
      link:                    link,
      'dc:type':               dcType,
      'dc:creator':            dcCreator,
      'dc:date':               dcDate,
      'dc:source':             dcSource,
      source:                  dcSource,
      date:                    dcDate,
      isoDate:                 dcDate,
      pubDate:                 dcDate,
      creator:                 dcCreator,
      description:             description,
      content:                 encoded || description,
      'content:encoded':       encoded,
      'content:encodedSnippet': description,
      contentSnippet:          description,
      guid:                    link,
    }
  };
}).filter(item => item.json.link !== '');

