const items = $input.all();
const results = [];
for (const item of items) {
  const json = item.json;
  let loopItem = {};
  try { loopItem = $('Loop Over Items1').first().json; } catch(e) { loopItem = {}; }
  const sourceName = (loopItem.Name || json.source || '未知来源').trim();
  const priority = (loopItem.Priority || 'A').toString().toUpperCase();
  let authorStr = json.creator || json['dc:creator'] || json.author || '';
  let instStr = '';
  if (json.metadata) {
    if (json.metadata.citation_author) authorStr = Array.isArray(json.metadata.citation_author) ? json.metadata.citation_author[0] + '等' : json.metadata.citation_author;
    if (json.metadata.citation_author_institution) instStr = Array.isArray(json.metadata.citation_author_institution) ? json.metadata.citation_author_institution[0] : json.metadata.citation_author_institution;
  }
  const authorInfo = (instStr ? '机构：' + instStr + ' | ' : '') + (authorStr ? '作者：' + authorStr : '');
  const rawTitle = (json.title || '').trim();
  const rawLink = json.link || json.guid || '';
  const rawBody = json['content:encoded'] || json.content || json.article_content || '';
  const rawSnippet = json.description || json.contentSnippet || '';
  function deepClean(text) {
    if (!text) return '';
    return text.replace(/<script[\s\S]*?<\/script>/gi,'').replace(/<style[\s\S]*?<\/style>/gi,'').replace(/<!--[\s\S]*?-->/g,'').replace(/<img[^>]*>/gi,'').replace(/<a[^>]*>(.*?)<\/a>/gi,'$1').replace(/<\/?(?:div|span|p|br|hr|ul|ol|li|table|tr|td|th|thead|tbody|header|footer|nav|aside|section|article|figure|figcaption|h[1-6])[^>]*>/gi,' ').replace(/<[^>]+>/g,'').replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<').replace(/&gt;/gi,'>').replace(/&quot;/gi,'"').replace(/&#\d+;/g,' ').replace(/&[a-zA-Z]+;/g,' ').replace(/\{[^}]{0,200}\}/g,' ').replace(/\s+/g,' ').trim();
  }
  const cleanBody = deepClean(rawBody);
  const cleanSnippet = deepClean(rawSnippet);
  let contentForAI = '标题：' + rawTitle + '\n';
  if (authorInfo) contentForAI += '研究团队：' + authorInfo + '\n';
  if (cleanBody.length > 200) contentForAI += '正文：' + cleanBody;
  else if (cleanSnippet.length > 50) { contentForAI += '摘要：' + cleanSnippet; if (cleanBody.length > 0) contentForAI += '\n补充：' + cleanBody; }
  else contentForAI += '内容：' + (cleanBody || cleanSnippet || '仅有标题，无正文或摘要');
  const textLen = contentForAI.replace(/标题：.*\n/,'').replace(/研究团队：.*\n/,'').length;
  let infoQuality = 'rich';
  if (textLen < 100) infoQuality = 'title_only';
  else if (textLen < 200) infoQuality = 'thin';
  const maxLen = infoQuality === 'rich' ? 8000 : 6000;
  if (contentForAI.length > maxLen) contentForAI = contentForAI.substring(0, maxLen);
  results.push({ json: { content_for_ai: contentForAI, info_quality: infoQuality, source_name: sourceName, original_title: rawTitle, original_link: rawLink, link: rawLink, priority: priority, title: rawTitle, Journal_Name: sourceName, Impact_Factor: loopItem.Impact_Factor || '', Manual_Stars: loopItem.Manual_Stars || '', Priority: priority, Description: loopItem.Description || '', Topic_Tags: loopItem.Topic_Tags || '', Category: loopItem.Category || '' } });
}
return results;

const items = $input.all();
const allOriginals = $('按信息质量分流1').all();

const results = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const orig = allOriginals[i]?.json || {};

  let pass = false, reason = '';
  try {
    // 兼容 Agent节点(output) 和 HTTP Request节点(choices)
    let content = item.json.output || item.json.choices?.[0]?.message?.content || '';

    // 去掉markdown代码块标记
    content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    // 如果没有花括号，手动补上
    if (!content.startsWith('{')) {
      content = '{' + content + '}';
    }

    const fo = content.indexOf('{'), lc = content.lastIndexOf('}');
    if (fo !== -1 && lc !== -1) {
      const p = JSON.parse(content.substring(fo, lc + 1));
      pass = p.pass === true;
      reason = p.reason || '';
    }
  } catch(e) { pass = false; reason = '解析失败: ' + e.message; }

  results.push({
    json: {
      ...orig,
      gatekeeper_pass: pass,
      gatekeeper_reason: reason
    }
  });
}
return results;

const items = $input.all();
let finalReport = "";

// === 0. 获取当前日期 ===
const today = new Date();
const dateStr = `${today.getMonth() + 1}月${today.getDate()}日`;
finalReport += `📅 **长寿抗衰日报 | ${dateStr}**\n\n`;

// === 1. 数据分桶 (先分类，再生成) ===
let sLevelItems = [];
let aLevelItems = [];

for (const item of items) {
  // 忽略不相关的内容
  if (item.json.is_relevant === false) continue;

  // 获取优先级 (防呆：转大写，处理 undefined)
  const priority = (item.json.Priority || "").toString().toUpperCase();

  // 获取摘要 (关键修正：读取 summary 字段)
  const summary = item.json.summary || item.json.text || "摘要生成失败";

  // 准备好要在报告里用的数据对象
  const reportItem = {
    title: item.json.title,
    summary: summary,
    link: item.json.link,
    source: item.json.Journal_Name || item.json.source_name || "来源未知",
    ifScore: item.json.Impact_Factor || "",
    stars: item.json.Manual_Stars || ""
  };

  if (priority.includes('S')) {
    sLevelItems.push(reportItem);
  } else {
    // 剩下的都归为 A 级 (包括 A级、空值等)
    aLevelItems.push(reportItem);
  }
}

// === 2. 生成 S 级板块 (重磅) ===
finalReport += `🚀 **【重磅关注】**\n`;
if (sLevelItems.length > 0) {
  sLevelItems.forEach((item, index) => {
    // 格式：标题
    finalReport += `**${item.title}**\n`;

    // 格式：来源 + IF (如果有)
    let metaInfo = `📜 ${item.source}`;
    if (item.ifScore && item.ifScore != '0') metaInfo += ` (IF: ${item.ifScore})`;
    if (item.stars) metaInfo += ` ${item.stars}`;
    finalReport += `${metaInfo}\n`;

    // 格式：摘要 (S级摘要通常较长，直接放)
    finalReport += `${item.summary}\n`;
    finalReport += `🔗 (${item.link})\n\n`; // Markdown链接更整洁
    if (index < sLevelItems.length - 1) finalReport += `————————————\n\n`;
  });
} else {
  finalReport += `(今日暂无 S 级重磅更新)\n\n`;
}

finalReport += `————————————\n\n`; // S和A之间的分割线

// === 3. 生成 A 级板块 (简讯) ===
finalReport += `📰 **【行业简讯】**\n\n`;
if (aLevelItems.length > 0) {
  aLevelItems.forEach((item, index) => {
    // 像 S 级一样，标题独立成行，去掉数字序号
    finalReport += `**${item.title}**\n`;

    // 摘要紧跟其后，去掉缩进，更利于阅读
    finalReport += `${item.summary}\n`;

    // 统一改成友好的 Markdown 超链接格式
    finalReport += `🔗 (${item.link})\n\n`;

    // 增加一条比 S 级稍轻的虚线分割线，提升排版质感
    if (index < aLevelItems.length - 1) finalReport += `┈┈┈┈┈┈┈┈┈┈┈┈\n\n`;
  });
} else {
  finalReport += `(今日暂无其他资讯)\n`;
}

// === 4. 输出 ===
return [{ json: { text_report: finalReport } }];

