// 从 Firecrawl 返回的 Markdown 中提取 Nature 文章摘要
// 替换原来解析HTML的「提取摘要和作者」节点
// 配对上游「24H以内1」保留 RSS 原始字段

function extractSection(markdown, sectionName) {
  const escaped = sectionName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp('##\\s+' + escaped + '\\s*\\n([\\s\\S]*?)(?=\\n##\\s|$)', 'i');
  const match = markdown.match(regex);
  if (match && match[1]) {
    return match[1]
      .replace(/!\[.*?\]\(.*?\)/g, '')
      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }
  return null;
}

