const originals = $('24H以内1').all();

return items.map((item, i) => {
  // Firecrawl 单页抓取结果在 data 下
  const markdown = item.json.data?.markdown || item.json.markdown || '';
  const metadata = item.json.data?.metadata || item.json.metadata || {};
  const orig = (originals[i] && originals[i].json) ? originals[i].json : {};

  // 按优先级提取摘要（Nature文章结构）
  const abstract =
    extractSection(markdown, 'Abstract') ||
    extractSection(markdown, 'Summary') ||
    extractSection(markdown, 'Main') ||
    metadata.description ||
    metadata.ogDescription ||
    orig.contentSnippet ||
    orig.content ||
    '';

  // 清理标题：去掉 " | Nature Metabolism" 等后缀
  const rawTitle = metadata.title || metadata.ogTitle || orig.title || '';
  const title = rawTitle.replace(/\s*\|.*$/, '').trim() || orig.title || '';

  // 提取作者（优先 metadata，回退 RSS dc:creator）
  const authorArr = metadata.citation_author;
  const authors = Array.isArray(authorArr)
    ? (authorArr.length > 3 ? authorArr.slice(0, 3).join(', ') + ' 等' : authorArr.join(', '))
    : (metadata.citation_author || orig.creator || orig['dc:creator'] || '');

  const fullAbstract = abstract;

  return {
    json: {
      // 下游 Edit Fields3 / 数据清洗V 需要的字段，保持与原 HTTP 版一致
      title:              title,
      link:               metadata.url || metadata.ogUrl || orig.link || '',
      pubDate:            orig.pubDate || orig.isoDate || '',
      isoDate:            orig.isoDate || orig.pubDate || '',
      creator:            authors,
      'dc:creator':       authors,
      full_abstract:      fullAbstract,
      content:            fullAbstract,
      'content:encoded':  fullAbstract,
      description:        fullAbstract,
      contentSnippet:     fullAbstract.substring(0, 300),
      guid:               orig.guid || '',
      categories:         orig.categories || '',
      extraction_note:    fullAbstract
        ? `Firecrawl成功提取${fullAbstract.length}字摘要`
        : '未提取到摘要，使用RSS原始内容'
    }
  };
});
